import React, { useState } from "react";
import axios from "axios";
import { FaLock } from "react-icons/fa";
import { useNavigate } from "react-router-dom";
import "./resetpassword.css";

const ResetPassword = () => {
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  
  const navigate = useNavigate();
  const userEmail = localStorage.getItem("resetEmail");

  if (!userEmail) {
    navigate("/forgot-password");
  }

  const handleResetPassword = async (e) => {
    e.preventDefault();
    setMessage("");
    setError("");

    if (!password || !confirmPassword) {
      setError("Both fields are required.");
      return;
    }

    if (password !== confirmPassword) {
      setError("Passwords do not match.");
      return;
    }

    try {
      setIsSubmitting(true);
      const response = await axios.post("http://localhost:5000/api/auth/reset-password", {
        email: userEmail,
        password,
      });
      
      if (response.data.success) {
        setMessage("Password reset successfully!");
        localStorage.removeItem("resetEmail");
        setTimeout(() => navigate("/login"), 1000);
      } else {
        setError(response.data.message || "Error resetting password.");
      }
    } catch (err) {
      setError("Server error. Try again.");
      console.error("Reset Password Error:", err);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="reset-password-container">
        <img src="/assets/ODCSE Logo.png" alt="Logo" className="logo" />
      <div className="reset-password-card">
        <h2>Reset Password</h2>
        <p>Enter your new password below.</p>

        <form onSubmit={handleResetPassword}>
          <div className="input-group">
            <FaLock className="icon" />
            <input
              type="password"
              placeholder="New Password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              disabled={isSubmitting}
            />
          </div>

          <div className="input-group">
            <FaLock className="icon" />
            <input
              type="password"
              placeholder="Confirm Password"
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              required
              disabled={isSubmitting}
            />
          </div>

          <button type="submit" className="reset-password-button" disabled={isSubmitting}>
            {isSubmitting ? "Resetting..." : "Reset Password"}
          </button>

          <div className="message-container">
            {message && <p className="success-message">{message}</p>}
            {error && <p className="error-message">{error}</p>}
          </div>
        </form>
      </div>

      <button onClick={() => navigate("/forgot-password")} className="back-button">
        Back
      </button>
    </div>
  );
};

export default ResetPassword;
